Status routeStm32Trigger(std::uint32_t trigger, std::uint32_t edge = BSP_ADC16_STM32_TRIGGER_EDGE_RISING) const
    {
        const AdcTriggerRoute route{.input = trigger, .output = edge, .invert = BSP_DISABLE, .type = BSP_ADC16_TRIGGER_OUTPUT_SAME_AS_INPUT};
        return routeSequenceTrigger(route);
    }

Status routeInjectedStm32Trigger(std::uint32_t trigger, std::uint32_t edge = BSP_ADC16_STM32_INJECTED_EDGE_RISING) const
    {
        const AdcTriggerRoute route{.input = trigger, .output = edge, .invert = BSP_DISABLE, .type = BSP_ADC16_TRIGGER_OUTPUT_SAME_AS_INPUT};
        return routePreemptionTrigger(route);
    }

extra_helpers:
static inline bsp_fdcan_frame_t toInternal(const CanFrame &frame)
{
    bsp_fdcan_frame_t internal{};
    internal.id = frame.id;
    internal.dlc = frame.dlc;
    internal.extended_id = frame.extendedId;
    internal.remote_frame = frame.remoteFrame;
    internal.fd_frame = frame.fdFrame;
    internal.bitrate_switch = frame.bitrateSwitch;
    internal.error_state_indicator = frame.errorStateIndicator;
    std::memcpy(internal.data, frame.data.data(), frame.data.size());
    return internal;
}

static inline CanFrame fromInternal(const bsp_fdcan_frame_t &frame)
{
    CanFrame publicFrame{};
    publicFrame.id = frame.id;
    publicFrame.dlc = frame.dlc;
    publicFrame.extendedId = frame.extended_id;
    publicFrame.remoteFrame = frame.remote_frame;
    publicFrame.fdFrame = frame.fd_frame;
    publicFrame.bitrateSwitch = frame.bitrate_switch;
    publicFrame.errorStateIndicator = frame.error_state_indicator;
    std::memcpy(publicFrame.data.data(), frame.data, publicFrame.data.size());
    return publicFrame;
}

methods:
Status initBitrate(std::uint32_t nominalBitrate, bool loopback = false) const
    {
        bsp_fdcan_config_t config{};
        const auto configStatus = defaultConfig(config, false);
        if (configStatus != Status::Ok) {
            return configStatus;
        }
        config.internal_loopback = loopback;
        const auto timingStatus = configureBitrate(config, nominalBitrate, 0U);
        if (timingStatus != Status::Ok) {
            return timingStatus;
        }
        return init(config);
    }

Status initFd(bool bitrateSwitch = true, bool loopback = false) const
    {
        bsp_fdcan_config_t config{};
        const auto configStatus = defaultConfig(config, true);
        if (configStatus != Status::Ok) {
            return configStatus;
        }
        config.bitrate_switch = bitrateSwitch;
        config.internal_loopback = loopback;
        return init(config);
    }

Status initFdBitrate(std::uint32_t nominalBitrate, std::uint32_t dataBitrate, bool bitrateSwitch = true, bool loopback = false) const
    {
        bsp_fdcan_config_t config{};
        const auto configStatus = defaultConfig(config, true);
        if (configStatus != Status::Ok) {
            return configStatus;
        }
        config.bitrate_switch = bitrateSwitch;
        config.internal_loopback = loopback;
        const auto timingStatus = configureBitrate(config, nominalBitrate, bitrateSwitch ? dataBitrate : nominalBitrate);
        if (timingStatus != Status::Ok) {
            return timingStatus;
        }
        return init(config);
    }

Status write(const CanFrame &frame) const
    {
        const auto internal = toInternal(frame);
        return statusFromInternal(bsp_fdcan_transmit(toInternal(id_), &internal));
    }

Status read(CanFrame &frame) const
    {
        bsp_fdcan_frame_t internal{};
        const auto status = statusFromInternal(bsp_fdcan_receive(toInternal(id_), &internal));
        if (status == Status::Ok) {
            frame = fromInternal(internal);
        }
        return status;
    }

Status loopback(const CanFrame &tx, CanFrame &rx) const
    {
        const auto internalTx = toInternal(tx);
        bsp_fdcan_frame_t internalRx{};
        const auto status = statusFromInternal(bsp_fdcan_loopback(toInternal(id_), &internalTx, &internalRx));
        if (status == Status::Ok) {
            rx = fromInternal(internalRx);
        }
        return status;
    }

Status filterMask(std::uint32_t id, std::uint32_t mask, bool extendedId = false, std::uint8_t filterIndex = 0) const
    {
        const bsp_fdcan_filter_t filter{.id = id, .mask = mask, .extended_id = extendedId, .filter_index = filterIndex};
        return statusFromInternal(bsp_fdcan_config_filter_mask(toInternal(id_), &filter));
    }

extra_helpers:
static constexpr bsp_tim_mode_t toInternal(TimerMode mode)
{
    switch (mode) {
    case TimerMode::Periodic:
        return BSP_TIM_MODE_PERIODIC;
    case TimerMode::Oneshot:
        return BSP_TIM_MODE_ONESHOT;
    case TimerMode::CaptureRising:
        return BSP_TIM_MODE_CAPTURE_RISING;
    case TimerMode::Compare:
        return BSP_TIM_MODE_COMPARE;
    }
    return BSP_TIM_MODE_PERIODIC;
}
